vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  //MilkDrop3 Flip Mode:
//vUv = 1-vUv; //Flipped in warp shader

float t = uTime; // set velocity here
vec2 c = (vUv-0.5)*uAspect.wz;
float1 ang_hq = atan(c.x,c.y);
vec2 spiral = vec2(ang_hq*q11*4+t,uAspect.w*log(length(c))+ang_hq*q11-t);
//spiral = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*0.83; // mirror
spiral = 0.5 - (0.5 - fract(spiral))*0.866; // mirror
vUv = 0.5 + (vUv-0.5)*0.88;
    ret = texture(sampler_main, vUv).xyz;
    ret *= 1.00; //gamma
 ret = mix(GetPixel(vUv).y*vec3(0.6,0,0),mix(1,vec3(1,0,0),GetBlur1(vUv).y),GetPixel(vUv).x*0.6);
// ret = mix(ret,vec3(1,0,0),GetPixel(spiral).y*audioLow*0.5);
// ret = mix(ret,1,GetPixel(spiral).x*audioHigh*0.25);
//MilkDrop3 Solarize Mode:
ret = ret*(1-ret)*4;
//MilkDrop3 Invert Mode:
ret = 1 - ret;

  fragColor = ret;
}
